static void
reset_init_stdio(struct proc *p)
{
  int fd;

  for(fd = 0; fd < NOFILE; fd++){
    if(p->ofile[fd]){
      fileclose(p->ofile[fd]);
      p->ofile[fd] = 0;
    }
  }

  for(fd = 0; fd < 3; fd++){
    struct file *f = filealloc();
    if(f == 0)
      panic("init stdio filealloc");
    f->type = FD_DEVICE;
    f->off = 0;
    f->ep = 0;
    f->major = CONSOLE;
    f->readable = 1;
    f->writable = 1;
    p->ofile[fd] = f;
  }
}

static void
reset_init_runtime(struct proc *p)
{
  p->killed = 0;
  p->timeslice = DEFAULT_TIMESLICE;
  p->slice_remain = DEFAULT_TIMESLICE;
}

static int
set_init_cwd(struct proc *p, char *path)
{
  struct dirent *ep = ename(path);
  if(ep == 0)
    return -1;
  if(p->cwd)
    eput(p->cwd);
  p->cwd = ep;
  return 0;
}

