// set up to take exceptions and traps while in the kernel.
void
trapinithart(void)
{
  w_stvec((uint64)kernelvec);
#ifdef VISIONFIVE2
  // Keep early VF2 bring-up fail-closed: install the trap vector, but
  // leave supervisor interrupts disabled until the timer/PLIC path is
  // wired to real VF2 devices instead of the inherited k210 layout.
  w_sie(0);
