      vf2_last_irq = irq;
      vf2_extirq_seen = 1;
			vf2_uart_intr();
		}
		else if (irq) {
      vf2_last_irq = irq;
      vf2_extirq_seen = 1;
			printf("unexpected VF2 interrupt irq = %d\n", irq);
		}

		if (irq) { plic_complete(irq);}

		return 1;
	}
	else if (0x8000000000000005L == scause) {
		timer_tick();
		return 2;
	}
	return 0;
