// Returns 0 on success, -1 on failure.
static int
loadseg(pagetable_t pagetable, uint64 va, struct dirent *ep, uint offset, uint sz)
{
  uint i, n;
  uint64 va0, pa;

  for(i = 0; i < sz; i += n){
    va0 = PGROUNDDOWN(va + i);
    pa = walkaddr(pagetable, va0);
    if(pa == NULL)
      panic("loadseg: address should exist");
    n = PGSIZE - ((va + i) - va0);
    if(n > sz - i)
      n = sz - i;
    if(eread(ep, 0, pa + ((va + i) - va0), offset+i, n) != n)
      return -1;
  }

  return 0;
}


int exec(char *path, char **argv)
{
  char *s, *last;
  int i, off;
  uint64 argc, sz = 0, sp, argbase, ustack[MAXARG+1], stackbase;
  uint64 load_end = 0, phdr_addr = 0, heapbase, stacktop, stackpage;
  struct elfhdr elf;
  struct dirent *ep;
  struct proghdr ph;
  pagetable_t pagetable = 0, oldpagetable;
  pagetable_t kpagetable = 0, oldkpagetable;
  struct proc *p = myproc();

  // Make a copy of p->kpt without old user space, 
  // but with the same kstack we are using now, which can't be changed
  if ((kpagetable = (pagetable_t)kalloc()) == NULL) {
    return -1;
  }
  memmove(kpagetable, p->kpagetable, PGSIZE);
  for (int i = 0; i < PX(2, MAXUVA); i++) {
    kpagetable[i] = 0;
  }

  if((ep = ename(path)) == NULL) {
    #ifdef DEBUG
    printf("[exec] %s not found\n", path);
    #endif
    goto bad;
  }
  elock(ep);

  // Check ELF header
  if(eread(ep, 0, (uint64) &elf, 0, sizeof(elf)) != sizeof(elf))
    goto bad;
  if(elf.magic != ELF_MAGIC)
    goto bad;
  if((pagetable = proc_pagetable(p)) == NULL)
    goto bad;

  // Load program into memory.
  for(i=0, off=elf.phoff; i<elf.phnum; i++, off+=sizeof(ph)){
    if(eread(ep, 0, (uint64)&ph, off, sizeof(ph)) != sizeof(ph))
      goto bad;
    if(ph.type != ELF_PROG_LOAD)
      continue;
    if(ph.memsz < ph.filesz)
      goto bad;
    if(ph.vaddr + ph.memsz < ph.vaddr)
      goto bad;
    if(ph.vaddr + ph.memsz > load_end)
      load_end = ph.vaddr + ph.memsz;
    if(elf.phoff >= ph.off &&
       elf.phoff + elf.phnum * elf.phentsize <= ph.off + ph.filesz)
      phdr_addr = ph.vaddr + (elf.phoff - ph.off);
    uint64 sz1;
    if((sz1 = uvmalloc(pagetable, kpagetable, sz, ph.vaddr + ph.memsz)) == 0)
      goto bad;
    sz = sz1;
    if(loadseg(pagetable, ph.vaddr, ep, ph.off, ph.filesz) < 0)
      goto bad;
  }
  eunlock(ep);
  eput(ep);
  ep = 0;

  p = myproc();
  uint64 oldsz = p->sz;

  heapbase = PGROUNDUP(load_end);
  stacktop = heapbase + 16ULL * 1024ULL * 1024ULL;
  if(stacktop < heapbase || stacktop >= MAXUVA)
    goto bad;
  stackpage = stacktop - PGSIZE;
  char *stackmem = kalloc();
  if(stackmem == NULL)
    goto bad;
  memset(stackmem, 0, PGSIZE);
  if(mappages(pagetable, stackpage, PGSIZE, (uint64)stackmem,
              PTE_R | PTE_W | PTE_U) != 0){
    kfree(stackmem);
    goto bad;
  }
  if(mappages(kpagetable, stackpage, PGSIZE, (uint64)stackmem,
              PTE_R | PTE_W) != 0){
    vmunmap(pagetable, stackpage, 1, 1);
    goto bad;
  }
  sz = stacktop;
  sp = stacktop;
  stackbase = sp - PGSIZE;

  // Push argument strings, prepare rest of stack in ustack.
  for(argc = 0; argv[argc]; argc++) {
    if(argc >= MAXARG)
      goto bad;
    sp -= strlen(argv[argc]) + 1;
    sp -= sp % 16; // riscv sp must be 16-byte aligned
    if(sp < stackbase)
      goto bad;
    if(copyout(pagetable, sp, argv[argc], strlen(argv[argc]) + 1) < 0)
      goto bad;
    ustack[argc] = sp;
  }
  ustack[argc] = 0;

  char platform[] = "riscv64";
  char random[16];
  uint64 platform_addr, random_addr;
  memset(random, 0, sizeof(random));

  sp -= sizeof(random);
  sp -= sp % 16;
  if(sp < stackbase)
    goto bad;
  random_addr = sp;
  if(copyout(pagetable, random_addr, random, sizeof(random)) < 0)
    goto bad;

  sp -= sizeof(platform);
  sp -= sp % 16;
  if(sp < stackbase)
    goto bad;
  platform_addr = sp;
  if(copyout(pagetable, platform_addr, platform, sizeof(platform)) < 0)
    goto bad;

  // Push a Linux-compatible initial stack with enough auxv for libc.
  // We still pass a1 = argv for the xv6 direct-main test binaries.
  uint64 auxv[] = {
    3, phdr_addr,             // AT_PHDR
    4, elf.phentsize,         // AT_PHENT
    5, elf.phnum,             // AT_PHNUM
    6, PGSIZE,                // AT_PAGESZ
    7, 0,                     // AT_BASE
    8, 0,                     // AT_FLAGS
    9, elf.entry,             // AT_ENTRY
    11, 0,                    // AT_UID
    12, 0,                    // AT_EUID
    13, 0,                    // AT_GID
    14, 0,                    // AT_EGID
    15, platform_addr,        // AT_PLATFORM
    16, 0,                    // AT_HWCAP
    17, 100,                  // AT_CLKTCK
    23, 0,                    // AT_SECURE
    25, random_addr,          // AT_RANDOM
    31, ustack[0],            // AT_EXECFN
    0, 0,
  };
  sp -= (1 + argc + 1 + 1 + NELEM(auxv)) * sizeof(uint64);
  sp -= sp % 16;
  if(sp < stackbase)
    goto bad;
  argbase = sp + sizeof(uint64);
  if(copyout(pagetable, argbase, (char *)ustack, (argc+1)*sizeof(uint64)) < 0)
    goto bad;
  uint64 zero = 0;
  if(copyout(pagetable, argbase + (argc+1)*sizeof(uint64),
             (char *)&zero, sizeof(zero)) < 0)
    goto bad;
  if(copyout(pagetable, argbase + (argc+2)*sizeof(uint64),
             (char *)auxv, sizeof(auxv)) < 0)
    goto bad;
  if(copyout(pagetable, sp, (char *)&argc, sizeof(argc)) < 0)
    goto bad;

  // arguments to user main(argc, argv)
  // argc is returned via syscall return value (a0), and argv via a1.
  p->trapframe->a1 = argbase;

  // Save program name for debugging.
  for(last=s=path; *s; s++)
    if(*s == '/')
      last = s+1;
  safestrcpy(p->name, last, sizeof(p->name));

  // Commit to the user image.
  oldpagetable = p->pagetable;
  oldkpagetable = p->kpagetable;
  p->pagetable = pagetable;
  p->kpagetable = kpagetable;
  p->sz = sz;
  p->brk = heapbase;
  p->trapframe->epc = elf.entry;  // initial program counter = main
  p->trapframe->sp = sp; // initial stack pointer
  proc_freepagetable(oldpagetable, oldsz);
  w_satp(MAKE_SATP(p->kpagetable));
  sfence_vma();
  kvmfree(oldkpagetable, 0);
  return argc; // this ends up in a0, the first argument to main(argc, argv)

 bad:
  #ifdef DEBUG
  printf("[exec] reach bad\n");
  #endif
  if(pagetable)
    proc_freepagetable(pagetable, sz);
  if(kpagetable)
    kvmfree(kpagetable, 0);
  if(ep){
    eunlock(ep);
    eput(ep);
  }
  return -1;
}

