    if(run_next_init_test(p, status) >= 0){
      return;
    }
#endif
    printf("init exiting, shutdown qemu\n");
    sbi_shutdown();
    for(;;) {}
  }

  // Close all open files.
  for(int fd = 0; fd < NOFILE; fd++){
    if(p->ofile[fd]){
      struct file *f = p->ofile[fd];
      fileclose(f);
      p->ofile[fd] = 0;
    }
  }

  eput(p->cwd);
  p->cwd = 0;

