// Physical memory allocator, for user processes,
// kernel stacks, page-table pages,
// and pipe buffers. Allocates whole 4096-byte pages.


#include "include/types.h"
#include "include/param.h"
#include "include/memlayout.h"
#include "include/riscv.h"
#include "include/spinlock.h"
#include "include/kalloc.h"
#include "include/string.h"
#include "include/printf.h"

void freerange(void *pa_start, void *pa_end);

extern char kernel_end[]; // first address after kernel.

struct run {
  struct run *next;
};

struct {
  struct spinlock lock;
  struct run *freelist;
  uint64 npage;       // free pages in allocator
  uint64 total_pages; // pages managed by allocator
  int refcnt[(PHYSTOP - KERNBASE) / PGSIZE];
} kmem;

static inline int
pa2idx(uint64 pa)
{
  return (pa - KERNBASE) / PGSIZE;
}

void
kinit()
{
  initlock(&kmem.lock, "kmem");
  kmem.freelist = 0;
  kmem.npage = 0;
  kmem.total_pages = 0;
  memset(kmem.refcnt, 0, sizeof(kmem.refcnt));
  freerange(kernel_end, (void*)PHYSTOP);
  kmem.total_pages = kmem.npage;
  #ifdef DEBUG
  printf("kernel_end: %p, phystop: %p\n", kernel_end, (void*)PHYSTOP);
  printf("kinit\n");
  #endif
}

void
freerange(void *pa_start, void *pa_end)
{
  char *p;
  p = (char*)PGROUNDUP((uint64)pa_start);
  for(; p + PGSIZE <= (char*)pa_end; p += PGSIZE){
    acquire(&kmem.lock);
    kmem.refcnt[pa2idx((uint64)p)] = 1;
    release(&kmem.lock);
    kfree(p);
  }
}

// Free the page of physical memory pointed at by v,
// which normally should have been returned by a
// call to kalloc().  (The exception is when
// initializing the allocator; see kinit above.)
void
kfree(void *pa)
{
  struct run *r;
  uint64 idx;

  if(((uint64)pa % PGSIZE) != 0 || (char*)pa < kernel_end || (uint64)pa >= PHYSTOP)
    panic("kfree");
  idx = pa2idx((uint64)pa);

  acquire(&kmem.lock);
  if(kmem.refcnt[idx] < 1)
    panic("kfree ref");
  kmem.refcnt[idx]--;
  if(kmem.refcnt[idx] == 0){
    // Fill with junk to catch dangling refs.
    memset(pa, 1, PGSIZE);
    r = (struct run*)pa;
    r->next = kmem.freelist;
    kmem.freelist = r;
    kmem.npage++;
  }
  release(&kmem.lock);
}

// Allocate one 4096-byte page of physical memory.
// Returns a pointer that the kernel can use.
// Returns 0 if the memory cannot be allocated.
void *
kalloc(void)
{
  struct run *r;
  int idx;

  acquire(&kmem.lock);
  r = kmem.freelist;
  if(r) {
    kmem.freelist = r->next;
    idx = pa2idx((uint64)r);
    kmem.refcnt[idx] = 1;
    kmem.npage--;
  }
  release(&kmem.lock);

  if(r)
    memset((char*)r, 5, PGSIZE); // fill with junk
  return (void*)r;
}

uint64
freemem_amount(void)
{
  return kmem.npage << PGSHIFT;
}

int
kallocated_pages(void)
{
  int used;

  acquire(&kmem.lock);
  used = (int)(kmem.total_pages - kmem.npage);
  release(&kmem.lock);
  return used;
}

void
kaddref(void *pa)
{
  uint64 idx;

  if(((uint64)pa % PGSIZE) != 0 || (char*)pa < kernel_end || (uint64)pa >= PHYSTOP)
    panic("kaddref");
  idx = pa2idx((uint64)pa);

  acquire(&kmem.lock);
  if(kmem.refcnt[idx] < 1)
    panic("kaddref ref");
  kmem.refcnt[idx]++;
  release(&kmem.lock);
}

int
kgetref(void *pa)
{
  uint64 idx;
  int ref;

  if(((uint64)pa % PGSIZE) != 0 || (char*)pa < kernel_end || (uint64)pa >= PHYSTOP)
    panic("kgetref");
  idx = pa2idx((uint64)pa);

  acquire(&kmem.lock);
  ref = kmem.refcnt[idx];
  release(&kmem.lock);
  return ref;
}

