static int
streq(const char *a, const char *b)
{
  char ca, cb;
  while(*a && *b){
    ca = *a;
    cb = *b;
    if(ca >= 'A' && ca <= 'Z')
      ca = ca - 'A' + 'a';
    if(cb >= 'A' && cb <= 'Z')
      cb = cb - 'A' + 'a';
    if(ca != cb)
      return 0;
    a++;
    b++;
  }
  return *a == 0 && *b == 0;
}

