{
  static const char *linux_bins[] = {
    "times", "execve", "dup", "clone", "read", "exit", "fork", "sleep",
    "mmap", "munmap", "getdents", "mkdir_", "mkdir", "chdir", "dup2",
    "waitpid", "fstat", "pipe", "getpid", "wait", "uname", "open",
    "gettimeofday", "getppid", "openat", "brk", "yield", "umount",
    "unlink", "mount", "getcwd", "write", "close", "test_echo", "lua",
    "busybox", "runtest.exe", "entry-static.exe", "entry-static.ex",
    "entry-dynamic.exe", "entry-dynamic.e",
