}

static int
fd_get(int fd, struct file **pf)
{
  struct proc *p = myproc();

  if(fd < 0 || fd >= NOFILE || p->ofile[fd] == 0)
    return -1;
  *pf = p->ofile[fd];
  return 0;
}

static int
linux_open_flags_to_xv6(int flags)
{
  int out = O_RDONLY;

  if(flags & LINUX_O_RDWR)
    out = O_RDWR;
  else if(flags & LINUX_O_WRONLY)
    out = O_WRONLY;

  if(flags & LINUX_O_CREAT)
    out |= O_CREATE;
  if(flags & LINUX_O_TRUNC)
    out |= O_TRUNC;
  if(flags & LINUX_O_APPEND)
    out |= O_APPEND;

  return out;
}

static int
linux_begin_dirfd_cwd(int dirfd, uint64 path_addr, char *pathbuf, struct dirent **oldcwd)
{
  struct file *f;
  struct proc *p = myproc();

  *oldcwd = 0;
  if(fetchstr(path_addr, pathbuf, FAT32_MAX_PATH) < 0)
    return -1;
  if(pathbuf[0] == '/' || dirfd == LINUX_AT_FDCWD)
    return 0;
  if(fd_get(dirfd, &f) < 0 || f->type != FD_ENTRY || !(f->ep->attribute & ATTR_DIRECTORY))
    return -1;

  *oldcwd = p->cwd;
  p->cwd = edup(f->ep);
  return 0;
}

static void
linux_end_dirfd_cwd(struct dirent *oldcwd)
{
  struct proc *p = myproc();

  if(oldcwd){
    eput(p->cwd);
    p->cwd = oldcwd;
  }
}

