linux_sys_dup3(void)
{
  int oldfd, newfd, flags;
  struct proc *p = myproc();
  struct file *f;

  if(argint(0, &oldfd) < 0 || argint(1, &newfd) < 0 || argint(2, &flags) < 0)
    return -1;
  if(flags != 0)
    return -1;

  if(fd_get(oldfd, &f) < 0)
    return -1;
  if(newfd < 0 || newfd >= NOFILE)
    return -1;
  if(oldfd == newfd)
    return newfd;

  if(p->ofile[newfd]){
    fileclose(p->ofile[newfd]);
    p->ofile[newfd] = 0;
  }
  p->ofile[newfd] = filedup(f);
  return newfd;
}

