static uint64
linux_sys_dup(void)
{
  int fd;
  struct proc *p = myproc();
  uint64 ret = sys_dup();

  if((long)ret < 0)
    return -24;

  fd = (int)ret;
  if((uint64)fd >= linux_rlimit_nofile){
    if(fd >= 0 && fd < NOFILE && p->ofile[fd]){
      struct file *f = p->ofile[fd];
      p->ofile[fd] = 0;
      fileclose(f);
    }
    return -24;
  }
  return ret;
}

