      lim.max = linux_rlimit_nofile_max;
    } else {
      lim.cur = 64ULL * 1024ULL * 1024ULL;
      lim.max = 64ULL * 1024ULL * 1024ULL;
    }
    if(copyout2(old_limit, (char *)&lim, sizeof(lim)) < 0)
      return -1;
  }
  if(new_limit != 0 && resource == 7){
    if(copyin2((char *)&newlim, new_limit, sizeof(newlim)) < 0)
      return -1;
    linux_rlimit_nofile = newlim.cur;
    if(linux_rlimit_nofile > NOFILE)
      linux_rlimit_nofile = NOFILE;
    linux_rlimit_nofile_max = newlim.max;
    if(linux_rlimit_nofile_max > NOFILE)
      linux_rlimit_nofile_max = NOFILE;
  }
  return 0;
}

