static uint64
linux_sys_nanosleep(void)
{
  uint64 req, rem;
  struct linux_timeval ts;
  uint64 total_usec, need_ticks;
  uint start;

  if(argaddr(0, &req) < 0 || argaddr(1, &rem) < 0)
    return -1;
  (void)rem;
  if(req == 0)
    return -1;
  if(copyin2((char *)&ts, req, sizeof(ts)) < 0)
    return -1;

  total_usec = ts.sec * USEC_PER_SEC + ts.usec;
  need_ticks = (total_usec + USEC_PER_TICK - 1) / USEC_PER_TICK;
  if(need_ticks == 0)
    return 0;

  acquire(&tickslock);
  start = ticks;
  while((uint64)(ticks - start) < need_ticks){
    if(myproc()->killed){
      release(&tickslock);
      return -1;
    }
    sleep(&ticks, &tickslock);
  }
  release(&tickslock);

  return 0;
}

