static void
linux_fill_kstat_from_entry(struct dirent *ep, struct linux_kstat *st)
{
  struct stat xst;

  memset(st, 0, sizeof(*st));
  st->st_nlink = 1;
  st->st_blksize = 512;

  elock(ep);
  estat(ep, &xst);
  eunlock(ep);

  st->st_dev = xst.dev;
  st->st_ino = ep ? ep->first_clus : 1;
  st->st_mode = (xst.type == T_DIR) ? LINUX_MODE_DIR : LINUX_MODE_FILE;
  st->st_size = xst.size;
  st->st_blocks = (xst.size + 511) / 512;
}

static void
linux_fill_kstat_device(int major, struct linux_kstat *st)
{
  memset(st, 0, sizeof(*st));
  st->st_nlink = 1;
  st->st_blksize = 512;
  st->st_mode = LINUX_MODE_CHR;
  st->st_rdev = major;
}

static uint64
linux_sys_fstat(void)
{
  int fd;
  uint64 addr;
  struct file *f;
  struct linux_kstat st;

  if(argint(0, &fd) < 0 || argaddr(1, &addr) < 0)
    return -1;
  if(fd_get(fd, &f) < 0)
    return -1;

  if(f->type == FD_ENTRY){
    linux_fill_kstat_from_entry(f->ep, &st);
  } else if(f->type == FD_DEVICE){
    linux_fill_kstat_device(f->major, &st);
  } else {
    memset(&st, 0, sizeof(st));
    st.st_nlink = 1;
    st.st_blksize = 512;
    st.st_mode = LINUX_MODE_FILE;
  }

  if(copyout2(addr, (char *)&st, sizeof(st)) < 0)
    return -1;
  return 0;
}

static uint64
linux_sys_newfstatat(void)
{
  int dirfd, flags;
  uint64 path_addr, addr;
  char pathbuf[FAT32_MAX_PATH];
  struct dirent *oldcwd;
  struct dirent *ep;
  struct file *f;
  struct linux_kstat st;
  int dev_major;

  if(argint(0, &dirfd) < 0 || argaddr(1, &path_addr) < 0 ||
     argaddr(2, &addr) < 0 || argint(3, &flags) < 0)
    return -1;
  (void)flags;

  if(fetchstr(path_addr, pathbuf, FAT32_MAX_PATH) < 0)
    return -1;
  linux_normalize_tmp_path(pathbuf);

  if(pathbuf[0] == 0){
    if(fd_get(dirfd, &f) < 0 || f->type != FD_ENTRY)
      return -1;
    linux_fill_kstat_from_entry(f->ep, &st);
    return copyout2(addr, (char *)&st, sizeof(st)) < 0 ? -1 : 0;
  }

  dev_major = linux_builtin_device_major(pathbuf);
  if(dev_major >= 0){
    linux_fill_kstat_device(dev_major, &st);
    return copyout2(addr, (char *)&st, sizeof(st)) < 0 ? -1 : 0;
  }

  if(linux_begin_dirfd_cwd(dirfd, path_addr, pathbuf, &oldcwd) < 0)
    return -1;
  linux_normalize_tmp_path(pathbuf);
  ep = ename(pathbuf);
  linux_end_dirfd_cwd(oldcwd);
  if(ep == 0)
    return -2;

  linux_fill_kstat_from_entry(ep, &st);
  eput(ep);
  return copyout2(addr, (char *)&st, sizeof(st)) < 0 ? -1 : 0;
}

static uint64
linux_sys_lseek(void)
{
  int fd, whence;
  uint64 off_u;
  long off;
  long base = 0;
  long newoff;
  struct file *f;
  struct stat st;

  if(argint(0, &fd) < 0 || argaddr(1, &off_u) < 0 || argint(2, &whence) < 0)
    return -1;
  if(fd_get(fd, &f) < 0)
    return -1;

  off = (long)off_u;
  if(whence == 0)
    base = 0;
  else if(whence == 1)
    base = f->off;
  else if(whence == 2){
    if(f->type != FD_ENTRY)
      return -1;
    elock(f->ep);
    estat(f->ep, &st);
    eunlock(f->ep);
    base = st.size;
  } else {
    return -1;
  }

  newoff = base + off;
  if(newoff < 0)
    return -1;
  f->off = newoff;
  return newoff;
}

static uint64
linux_sys_getdents64(void)
{
  int fd;
  uint64 addr, len;
  int count = 0, ret;
  struct file *f;
  struct dirent de;
  struct linux_dirent64 out;

  if(argint(0, &fd) < 0 || argaddr(1, &addr) < 0 || argaddr(2, &len) < 0)
    return -1;
  if(fd_get(fd, &f) < 0)
    return -1;
  if(f->type != FD_ENTRY || !(f->ep->attribute & ATTR_DIRECTORY))
    return -1;
  if(len < sizeof(out))
    return -1;

  elock(f->ep);
  while((ret = enext(f->ep, &de, f->off, &count)) == 0){
    f->off = ext4_active() ? de.off : f->off + count * 32;
  }
  if(ret == -1){
    eunlock(f->ep);
    return 0;
  }
  f->off = ext4_active() ? de.off : f->off + count * 32;
  eunlock(f->ep);

  memset(&out, 0, sizeof(out));
  out.d_ino = de.first_clus;
  out.d_off = f->off;
  out.d_reclen = sizeof(out);
  out.d_type = (de.attribute & ATTR_DIRECTORY) ? 4 : 8;
  safestrcpy(out.d_name, de.filename, sizeof(out.d_name));

  if(copyout2(addr, (char *)&out, sizeof(out)) < 0)
    return -1;
  return sizeof(out);
}

