static uint64
linux_sys_mmap(void)
{
  uint64 start, len, off;
  int prot, flags, fd;
  uint64 base;
  struct proc *p = myproc();
  struct file *f;

  if(argaddr(0, &start) < 0 || argaddr(1, &len) < 0 ||
     argint(2, &prot) < 0 || argint(3, &flags) < 0 ||
     argint(4, &fd) < 0 || argaddr(5, &off) < 0)
    return -1;

  (void)start;
  (void)prot;
  (void)flags;

  if(len == 0)
    return -1;

  base = p->sz;
  if(growproc((int)len) < 0)
    return -1;

  if(fd_get(fd, &f) == 0 && f->type == FD_ENTRY){
    elock(f->ep);
    eread(f->ep, 1, base, (uint)off, (uint)len);
    eunlock(f->ep);
  }

  return base;
}

