void
syscall(void)
{
  int num;
  int linux_abi;
  uint64 ret;
  struct proc *p = myproc();

  num = p->trapframe->a7;
  linux_abi = is_linux_abi_proc(p);

  // Linux ABI testcase binaries have syscall numbers that collide with xv6.
  // Dispatch them first for those processes.
  if(linux_abi && linux_dispatch(num, &ret)){
    p->trapframe->a0 = ret;
    return;
  }

  if(num > 0 && num < NELEM(syscalls) && syscalls[num]) {
    p->trapframe->a0 = syscalls[num]();
        // trace
    if ((p->tmask & (1 << num)) != 0) {
      printf("pid %d: %s -> %d\n", p->pid, sysnames[num], p->trapframe->a0);
    }
    return;
  }

  // For non-linux processes, still allow high-number Linux syscalls if needed.
  if(!linux_abi && linux_dispatch(num, &ret)){
    p->trapframe->a0 = ret;
    return;
  }

  printf("pid %d %s: unknown sys call %d\n",
          p->pid, p->name, num);
  p->trapframe->a0 = -1;
}

