{
  if(entry >= ext4_cache.entries && entry < ext4_cache.entries + ENTRY_CACHE_NUM)
    return entry - ext4_cache.entries;
  return -1;
}

static uint16
rd16(const uchar *p)
{
  uint16 v;
  memmove(&v, p, sizeof(v));
  return v;
}

static uint32
rd32(const uchar *p)
{
  uint32 v;
  memmove(&v, p, sizeof(v));
  return v;
}

static uint64
rd64_from_lohi(uint32 lo, uint16 hi)
{
  return ((uint64)hi << 32) | lo;
}

static int
disk_read_bytes(uint64 byte_off, int user_dst, uint64 dst, uint n)
{
  uint tot, m;
  uint sector_off;
  struct buf *b;

  for(tot = 0; tot < n; tot += m){
    b = bread(0, (uint)((byte_off + tot) / BSIZE));
    sector_off = (uint)((byte_off + tot) % BSIZE);
    m = BSIZE - sector_off;
    if(n - tot < m)
      m = n - tot;
    if(user_dst){
      if(either_copyout(1, dst + tot, b->data + sector_off, m) < 0){
        brelse(b);
        return -1;
      }
    } else {
      memmove((void *)(dst + tot), b->data + sector_off, m);
    }
    brelse(b);
  }
  return n;
}

static int
read_super(uchar *sb)
{
  return disk_read_bytes(EXT4_SUPER_OFFSET, 0, (uint64)sb, EXT4_SUPER_SIZE);
}

int
ext4_probe(void)
{
  uchar magic[2];
  if(disk_read_bytes(EXT4_SUPER_OFFSET + 56, 0, (uint64)magic, sizeof(magic)) != sizeof(magic))
    return 0;
  return rd16(magic) == EXT4_MAGIC;
}

static uint64
block_byte(uint64 block)
{
  return block * ext4.block_size;
}

static int
read_group_desc(uint32 group, uchar *gd)
{
  uint64 gd_table_block = (ext4.block_size == 1024) ? 2 : 1;
  uint64 off = block_byte(gd_table_block) + (uint64)group * ext4.desc_size;
  return disk_read_bytes(off, 0, (uint64)gd, ext4.desc_size);
}

static int
read_inode(uint32 ino, struct ext4_inode_info *out)
{
  uint32 idx, group, index;
  uint64 inode_table, inode_off;
  uchar gd[64];
  uchar raw[256];

  if(ino == 0 || ext4.inodes_per_group == 0 || ext4.inode_size > sizeof(raw))
    return -1;

  idx = ino - 1;
  group = idx / ext4.inodes_per_group;
  index = idx % ext4.inodes_per_group;

  if(read_group_desc(group, gd) < 0)
    return -1;

  inode_table = rd32(gd + 8);
  inode_off = block_byte(inode_table) + (uint64)index * ext4.inode_size;
  if(disk_read_bytes(inode_off, 0, (uint64)raw, ext4.inode_size) != ext4.inode_size)
    return -1;

  out->mode = rd16(raw + 0);
  out->size = rd32(raw + 4);
  out->flags = rd32(raw + 32);
  memmove(out->block, raw + 40, sizeof(out->block));
  return 0;
}

static int
extent_map_from_disk(uint64 extent_block, int depth, uint32 lblock, uint64 *pblock);

static int
extent_map_from_mem(uchar *base, int depth, uint32 lblock, uint64 *pblock)
{
  uint16 magic, entries;
  int i, chosen;
  uint32 ee_block, ee_len, ee_start_lo;
  uint16 ee_start_hi;
  uint32 ei_block, ei_leaf_lo;
  uint16 ei_leaf_hi;

  magic = rd16(base);
  entries = rd16(base + 2);
  if(magic != EXT4_EXT_MAGIC)
    return -1;

  if(depth == 0){
    for(i = 0; i < entries && 12 + i * 12 + 12 <= 60; i++){
      uchar *e = base + 12 + i * 12;
      ee_block = rd32(e);
      ee_len = rd16(e + 4) & 0x7fff;
      ee_start_hi = rd16(e + 6);
      ee_start_lo = rd32(e + 8);
      if(ee_len != 0 && lblock >= ee_block && lblock < ee_block + ee_len){
        *pblock = rd64_from_lohi(ee_start_lo, ee_start_hi) + (lblock - ee_block);
        return 0;
      }

