static int
extent_map_from_disk(uint64 extent_block, int depth, uint32 lblock, uint64 *pblock)
{
  uchar hdr[12];
  uchar ent[12];
  uint16 magic, entries;
  uint64 off;
  int i, chosen;
  uint32 ee_block, ee_len, ee_start_lo;
  uint16 ee_start_hi;
  uint32 ei_block, ei_leaf_lo;
  uint16 ei_leaf_hi;

  off = block_byte(extent_block);
  if(disk_read_bytes(off, 0, (uint64)hdr, sizeof(hdr)) != sizeof(hdr))
    return -1;
  magic = rd16(hdr);
  entries = rd16(hdr + 2);
  if(magic != EXT4_EXT_MAGIC)
    return -1;

  if(depth == 0){
    for(i = 0; i < entries; i++){
      if(disk_read_bytes(off + 12 + i * 12, 0, (uint64)ent, sizeof(ent)) != sizeof(ent))
        return -1;
      ee_block = rd32(ent);
      ee_len = rd16(ent + 4) & 0x7fff;
      ee_start_hi = rd16(ent + 6);
      ee_start_lo = rd32(ent + 8);
      if(ee_len != 0 && lblock >= ee_block && lblock < ee_block + ee_len){
        *pblock = rd64_from_lohi(ee_start_lo, ee_start_hi) + (lblock - ee_block);
        return 0;
      }
    }
    return -1;
  }

  chosen = -1;
  for(i = 0; i < entries; i++){
    if(disk_read_bytes(off + 12 + i * 12, 0, (uint64)ent, sizeof(ent)) != sizeof(ent))
      return -1;
    ei_block = rd32(ent);
    if(lblock >= ei_block)
      chosen = i;
    else
      break;
  }
  if(chosen < 0)
    return -1;

  if(disk_read_bytes(off + 12 + chosen * 12, 0, (uint64)ent, sizeof(ent)) != sizeof(ent))
    return -1;
  ei_leaf_lo = rd32(ent + 4);
  ei_leaf_hi = rd16(ent + 8);
  return extent_map_from_disk(rd64_from_lohi(ei_leaf_lo, ei_leaf_hi), depth - 1, lblock, pblock);
}

static int
map_inode_block(struct ext4_inode_info *ino, uint32 lblock, uint64 *pblock)
{
  int depth;
  if((ino->flags & EXT4_EXTENTS_FL) == 0)
    return -1;
  depth = rd16(ino->block + 6);
  return extent_map_from_mem(ino->block, depth, lblock, pblock);
}

static int
inode_read_bytes(uint32 ino_no, int user_dst, uint64 dst, uint off, uint n)
{
  struct ext4_inode_info ino;
  uint tot, m, block_off;
  uint64 pblock;

  if(read_inode(ino_no, &ino) < 0)
    return -1;
  if(off > ino.size || off + n < off)
    return 0;
  if(off + n > ino.size)
    n = ino.size - off;

  for(tot = 0; tot < n; tot += m){
    uint32 lblock = (off + tot) / ext4.block_size;
    block_off = (off + tot) % ext4.block_size;
    m = ext4.block_size - block_off;
    if(n - tot < m)
      m = n - tot;

    if(map_inode_block(&ino, lblock, &pblock) < 0){
      uint done = 0;
      while(done < m){
        uint z = m - done;
        if(z > BSIZE)
          z = BSIZE;
        if(user_dst){
          if(either_copyout(1, dst + tot + done, zero_sector, z) < 0)
            return -1;
        } else {
          memset((void *)(dst + tot + done), 0, z);
        }
        done += z;
      }
