  ep->ref = 1;
  ep->first_clus = ino_no;
  ep->cur_clus = ino_no;
  ep->file_size = ino->size;
  ep->attribute = 0;
  if((ino->mode & EXT4_S_IFMT) == EXT4_S_IFDIR)
