    struct dirent *parent = entry->parent;
    int idx = entry_cache_index(entry);
    if(idx >= 0)
      memset(virtual_file_data[idx], 0, EXT4_VFILE_CAP);
    entry->dirty = 0;
    entry->parent = 0;
    release(&ext4_cache.lock);
    if(parent && parent != entry)
      ext4_eput(parent);
    return;
  }
  if(entry != &ext4_root && entry->dirty && entry->ref == 0){
    release(&ext4_cache.lock);
    return;
  }
  if(entry != &ext4_root && entry->ref == 0){
    struct dirent *parent = entry->parent;
    entry->valid = 0;
    entry->parent = 0;
    release(&ext4_cache.lock);
    if(parent && parent != entry)
      ext4_eput(parent);
    return;
  }
  release(&ext4_cache.lock);
}

