static int
dir_find(uint32 dir_ino, char *name, uint32 *ino_out, char *name_out)
{
  struct ext4_inode_info din;
  uint off = 0;
  uchar hdr[8];
  char ent_name[EXT4_NAME_LEN + 1];
  uint32 ino;
  uint16 rec_len;
  uint8 name_len;

  if(read_inode(dir_ino, &din) < 0)
    return -1;
  while(off + sizeof(hdr) <= din.size){
    if(inode_read_bytes(dir_ino, 0, (uint64)hdr, off, sizeof(hdr)) != sizeof(hdr))
      return -1;
    ino = rd32(hdr);
    rec_len = rd16(hdr + 4);
    name_len = hdr[6];
    if(rec_len < 8 || off + rec_len > din.size + ext4.block_size)
      return -1;
    if(ino != 0 && name_len <= EXT4_NAME_LEN && name_len + 8 <= rec_len){
      memset(ent_name, 0, sizeof(ent_name));
      if(inode_read_bytes(dir_ino, 0, (uint64)ent_name, off + 8, name_len) != name_len)
        return -1;
      ent_name[name_len] = 0;
      if(strncmp(ent_name, name, EXT4_NAME_LEN) == 0){
        *ino_out = ino;
        if(name_out)
          safestrcpy(name_out, ent_name, EXT4_NAME_LEN + 1);
        return 0;
      }
    }
    off += rec_len;
  }
  return -1;
}

struct dirent *
ext4_dirlookup(struct dirent *dp, char *filename, uint *poff)
{
  uint32 ino_no;
  struct ext4_inode_info ino;
  struct dirent *ep;
  char found[EXT4_NAME_LEN + 1];
  int attr, data_id;

  if(poff)
    *poff = 0;
  if(!(dp->attribute & ATTR_DIRECTORY))
    return 0;
  if(strncmp(filename, ".", EXT4_NAME_LEN) == 0)
    return ext4_edup(dp);
  if(strncmp(filename, "..", EXT4_NAME_LEN) == 0)
    return ext4_edup(dp->parent ? dp->parent : &ext4_root);

  if((ep = virtual_lookup(dp, filename)) != 0)
    return ep;

  if(dir_find(dp->first_clus, filename, &ino_no, found) < 0)
  {
    if(virtual_spec(filename, &attr, &data_id))
      return virtual_create(dp, filename, attr, data_id);
    return 0;
  }
  if(read_inode(ino_no, &ino) < 0)
    return 0;
  ep = alloc_entry();
  if(ep == 0)
    return 0;
  fill_entry_from_inode(ep, ino_no, found, &ino);
  ep->parent = ext4_edup(dp);
  return ep;
}

static char *
skip_elem(char *path, char *name)
{
  char *s;
  int len;

  while(*path == '/')
    path++;
  if(*path == 0)
    return 0;
  s = path;
  while(*path != '/' && *path != 0)
    path++;
  len = path - s;
  if(len > EXT4_NAME_LEN)
    len = EXT4_NAME_LEN;
  memmove(name, s, len);
  name[len] = 0;
  while(*path == '/')
    path++;
  return path;
}

static struct dirent *
lookup_path(char *path, int parent, char *name)
{
  struct dirent *entry, *next;

  if(*path == '/')
    entry = ext4_edup(&ext4_root);
  else if(*path != 0)
    entry = ext4_edup(myproc()->cwd);
  else
    return 0;

  while((path = skip_elem(path, name)) != 0){
    ext4_elock(entry);
    if(!(entry->attribute & ATTR_DIRECTORY)){
      ext4_eunlock(entry);
      ext4_eput(entry);
      return 0;
    }
    if(parent && *path == 0){
      ext4_eunlock(entry);
      return entry;
    }
    next = ext4_dirlookup(entry, name, 0);
    ext4_eunlock(entry);
    ext4_eput(entry);
    if(next == 0)
      return 0;
    entry = next;
  }

  if(parent){
    ext4_eput(entry);
    return 0;
  }
  return entry;
}

