    if(entry->clus_cnt == EXT4_VDATA_MMAP){
      data = virtual_data_ptr(entry->clus_cnt);
      size = virtual_data_size(entry->clus_cnt);
    } else {
      idx = entry_cache_index(entry);
      if(idx < 0)
        return -1;
      data = virtual_file_data[idx];
      size = entry->file_size;
      if(size > EXT4_VFILE_CAP)
        size = EXT4_VFILE_CAP;
    }
    if(off > size || off + n < off)
      return 0;
