static void
wait_target(int pid)
{
  int wpid;

  for(;;){
    wpid = wait((int *)0);
    if(wpid < 0 || wpid == pid){
      return;
    }
  }
}

static int
run_test(char *name, char *alt)
{
  int pid;
  char path[64];
  char *argv[] = {name, 0};

  pid = fork();
  if(pid < 0){
    printf("init: fork failed for %s\n", name);
    return -1;
  }
  if(pid == 0){
    exec(name, argv);

    if(alt){
      argv[0] = alt;
      exec(alt, argv);
      argv[0] = name;
    }

    // Fallback paths for different image layouts.
    strcpy(path, "/");
    strcat(path, name);
    exec(path, argv);

    strcpy(path, "riscv64/");
    strcat(path, name);
    exec(path, argv);

    strcpy(path, "/riscv64/");
    strcat(path, name);
    exec(path, argv);

    if(alt){
      strcpy(path, "/");
      strcat(path, alt);
      exec(path, argv);

      strcpy(path, "riscv64/");
      strcat(path, alt);
      exec(path, argv);

      strcpy(path, "/riscv64/");
      strcat(path, alt);
      exec(path, argv);
    }

    printf("init: exec failed for %s\n", name);
    exit(1);
  }

  wait_target(pid);
  return 0;
}

