#include "user.h"

#define SIZE   (1 << 12)
#define PGSIZE (1 << 12)

int
main(void)
{
  int initial_pages, after_init_pages, after_fork_pages;
  int write_sum = 0;
  int i, pid;
  char *mem;
  int sz;
  int delta_without_cow;

  printf("Testing Copy-on-Write\n");

  initial_pages = getpgcnt();
  printf("Initial physical pages: %d\n", initial_pages);

  mem = sbrk(SIZE);
  if(mem == (char *)-1){
    printf("sbrk failed\n");
    exit(1);
  }

  for(i = 0; i < SIZE; i++){
    mem[i] = i % 256;
    write_sum += mem[i];
  }

  after_init_pages = getpgcnt();
  printf("Physical pages after initialization: %d (should be +1)\n", after_init_pages);
  if(after_init_pages != initial_pages + 1){
    printf("ERROR: Expected %d pages, got %d\n", initial_pages + 1, after_init_pages);
    exit(1);
  }

  sz = getprocsz();
  delta_without_cow =
      (sz / PGSIZE)
      + 2 + 2 + 1
      + 2 + 1
      + 1
      + 1 + 2;

  pid = fork();
  if(pid < 0){
    printf("fork failed\n");
    exit(1);
  }

  after_fork_pages = getpgcnt();
  printf("Physical pages after fork: %d\n", after_fork_pages);
  if(after_fork_pages >= after_init_pages + delta_without_cow){
    printf("ERROR: Page count changed too much from %d to %d after fork without write\n",
           after_init_pages, after_fork_pages);
    exit(1);
  }

  if(pid == 0){
    int before_read, after_read, sum = 0, after_write;

    before_read = getpgcnt();
    printf("Physical pages before child read: %d\n", before_read);

    for(i = 0; i < SIZE; i++)
      sum += mem[i];
    printf("Child read sum: %d\n", sum);
    if(sum != write_sum){
      printf("ERROR: Data corruption. Sum should be %d, but got %d\n", write_sum, sum);
      exit(2);
    }

    after_read = getpgcnt();
    printf("Physical pages after child read: %d (should be same)\n", after_read);
    if(after_read != before_read){
      printf("ERROR: Page count changed after read\n");
      exit(3);
    }

    mem[0] = 0xFF;
    after_write = getpgcnt();
    printf("Physical pages after child write: %d (should be increased)\n", after_write);
    if(after_write < after_fork_pages + 1){
      printf("ERROR: Expected at least %d pages, got %d\n", after_fork_pages + 1, after_write);
      exit(1);
    }
    exit(0);
  } else {
    int status;
    int before_write, after_read, after_write;
    int sum = 0;

    wait(&status);
    printf("wait status:%d\n", status);

    before_write = getpgcnt();
    for(i = 0; i < SIZE; i++)
      sum += mem[i];
    printf("Parent read sum: %d\n", sum);
    if(sum != write_sum){
      printf("ERROR: Data corruption. Sum should be %d, but got %d\n", write_sum, sum);
      exit(1);
    }

    after_read = getpgcnt();
    printf("Physical pages after child exit: %d (should be same as before read)\n", after_read);
    if(after_read != before_write){
      printf("ERROR: Expected %d pages, got %d\n", before_write, after_read);
      exit(1);
    }

    mem[0] = 0xAA;
    after_write = getpgcnt();
    printf("Physical pages after parent write: %d (should be same)\n", after_write);
    if(after_write != after_read){
      printf("ERROR: Page count changed after parent write\n");
      exit(1);
    }
  }

  printf("Copy-on-Write Test Completed Successfully\n");
  exit(0);
}

