#define PRODUCER_COUNT 2
#define ITEMS_PER_PRODUCER 4

static void
producer(int id, int wfd)
{
  for(int i = 0; i < ITEMS_PER_PRODUCER; i++){
    int item = id * 100 + i;
    write(wfd, &item, sizeof(item));
    printf("Prod %d produced %d\n", id, item);
  }
  printf("Prod %d finished\n", id);
}

int
main(void)
{
  int pipefd[2];
  if(pipe(pipefd) < 0){
    printf("ERROR: Failed to create main pipe\n");
    exit(1);
  }

  for(int i = 0; i < PRODUCER_COUNT; i++){
    int pid = fork();
    if(pid < 0){
      printf("ERROR: fork failed\n");
      exit(1);
    }
    if(pid == 0){
      close(pipefd[0]);
      producer(i, pipefd[1]);
      close(pipefd[1]);
      exit(0);
    }
  }

  close(pipefd[1]);

  int expected = PRODUCER_COUNT * ITEMS_PER_PRODUCER;
  int count = 0;
  int item = 0;
  while(read(pipefd[0], &item, sizeof(item)) == sizeof(item)){
    printf("Consu 0 consumed %d\n", item);
    count++;
  }
  close(pipefd[0]);

  for(int i = 0; i < PRODUCER_COUNT; i++)
    wait(0);

  if(count != expected){
    printf("ERROR: Item count mismatch! consumed=%d expected=%d\n", count, expected);
    exit(1);
  }

  printf("SUCCESS: All produced items were correctly consumed!\n");
  printf("MPMC test completed successfully!\n");
  exit(0);
}

