void
sched(void)
{
  int intena;
  struct proc *p = myproc();

  if(!holding(&p->lock))
    panic("sched p->lock");
  if(mycpu()->noff != 1)
    panic("sched locks");
  if(p->state == RUNNING)
    panic("sched running");
  if(intr_get())
    panic("sched interruptible");

  intena = mycpu()->intena;
  swtch(&p->context, &mycpu()->context);
  mycpu()->intena = intena;
}

// Give up the CPU for one scheduling round.
void
yield(void)
{
  struct proc *p = myproc();
  acquire(&p->lock);
  p->state = RUNNABLE;
  sched();
  release(&p->lock);
}

void
mlfq_maybe_update_locked(struct proc *p)
{
  uint total = p->mlfq_cpu_ticks + p->mlfq_sleep_ticks;
  if(total < MLFQ_WINDOW)
    return;
  if(p->mlfq_cpu_ticks > p->mlfq_sleep_ticks){
    p->priority = clamp_priority(p->priority + 1);
  } else if(p->mlfq_sleep_ticks > p->mlfq_cpu_ticks){
    p->priority = clamp_priority(p->priority - 1);
  }
  p->mlfq_cpu_ticks = 0;
  p->mlfq_sleep_ticks = 0;
}

void
proc_on_timer_tick(void)
{
  struct proc *p = myproc();

  if(p == 0)
    return;

  acquire(&p->lock);
  if(proc_get_sched_algo() == SCHED_RR){
    if(p->timeslice < 1)
      p->timeslice = 1;
    if(p->slice_remain < 1 || p->slice_remain > p->timeslice)
      p->slice_remain = p->timeslice;
    p->slice_remain--;
  } else if(proc_get_sched_algo() == SCHED_MLFQ){
    p->mlfq_cpu_ticks++;
    mlfq_maybe_update_locked(p);
  }
  release(&p->lock);
}

void
proc_record_sleep(int ticks)
{
  struct proc *p = myproc();

  if(p == 0 || ticks <= 0)
    return;
  if(proc_get_sched_algo() != SCHED_MLFQ)
    return;

  acquire(&p->lock);
  p->mlfq_sleep_ticks += (uint)ticks;
  mlfq_maybe_update_locked(p);
  release(&p->lock);
}

int
proc_should_yield_on_tick(void)
{
  struct proc *p = myproc();
  int need = 1;

  if(p == 0)
    return 1;

  if(proc_get_sched_algo() == SCHED_RR){
    acquire(&p->lock);
    if(p->slice_remain <= 0){
      if(p->timeslice < 1)
        p->timeslice = 1;
      p->slice_remain = p->timeslice;
      need = 1;
    } else {
      need = 0;
    }
    release(&p->lock);
  }

  return need;
}

int
proc_set_timeslice(int ticks)
{
  struct proc *p = myproc();

  if(ticks < 1)
    return -1;

  acquire(&p->lock);
  p->timeslice = ticks;
  p->slice_remain = ticks;
  release(&p->lock);
  return 0;
}

int
proc_set_priority(int priority)
{
  struct proc *p = myproc();

  acquire(&p->lock);
  p->priority = clamp_priority(priority);
  release(&p->lock);
  return 0;
}

int
proc_get_priority(void)
{
  struct proc *p = myproc();
  int priority;

  acquire(&p->lock);
  priority = p->priority;
  release(&p->lock);
  return priority;
}

int
proc_set_sched_algo(int algo)
{
  struct proc *p;

  if(algo != SCHED_RR && algo != SCHED_PRIORITY && algo != SCHED_MLFQ)
    return -1;

  sched_algo = algo;
  rr_cursor = 0;

  for(p = proc; p < &proc[NPROC]; p++){
    acquire(&p->lock);
    if(algo == SCHED_RR){
      if(p->timeslice < 1)
        p->timeslice = 1;
      p->slice_remain = p->timeslice;
    } else if(algo == SCHED_MLFQ){
      p->mlfq_cpu_ticks = 0;
      p->mlfq_sleep_ticks = 0;
    }
    release(&p->lock);
  }
  return 0;
}

int
proc_get_sched_algo(void)
{
  return sched_algo;
}

// A fork child's very first scheduling by scheduler()
// will swtch to forkret.
void
forkret(void)
{
  // printf("run in forkret\n");
  static int first = 1;

  // Still holding p->lock from scheduler.
  release(&myproc()->lock);

  if (first) {
    // File system initialization must be run in the context of a
    // regular process (e.g., because it calls sleep), and thus cannot
    // be run from main().
    // printf("[forkret]first scheduling\n");
    first = 0;
    fat32_init();
    myproc()->cwd = ename("/");
  }

  usertrapret();
}

// Atomically release lock and sleep on chan.
// Reacquires lock when awakened.
void
sleep(void *chan, struct spinlock *lk)
{
  struct proc *p = myproc();

  // Must acquire p->lock in order to
  // change p->state and then call sched.
  // Once we hold p->lock, we can be
  // guaranteed that we won't miss any wakeup
  // (wakeup locks p->lock),
  // so it's okay to release lk.
  if(lk != &p->lock){  //DOC: sleeplock0
    acquire(&p->lock);  //DOC: sleeplock1
    release(lk);
  }

  // Go to sleep.
  p->chan = chan;
  p->state = SLEEPING;

  sched();

  // Tidy up.
  p->chan = 0;

  // Reacquire original lock.
  if(lk != &p->lock){
    release(&p->lock);
    acquire(lk);
  }
}

// Wake up all processes sleeping on chan.
// Must be called without any p->lock.
void
wakeup(void *chan)
{
  struct proc *p;

  for(p = proc; p < &proc[NPROC]; p++) {
    acquire(&p->lock);
    if(p->state == SLEEPING && p->chan == chan) {
      p->state = RUNNABLE;
    }
    release(&p->lock);
  }
}

// Wake up p if it is sleeping in wait(); used by exit().
// Caller must hold p->lock.
static void
wakeup1(struct proc *p)
{
  if(!holding(&p->lock))
    panic("wakeup1");
  if(p->chan == p && p->state == SLEEPING) {
    p->state = RUNNABLE;
  }
}

// Kill the process with the given pid.
// The victim won't exit until it tries to return
// to user space (see usertrap() in trap.c).
int
kill(int pid)
{
  struct proc *p;

  for(p = proc; p < &proc[NPROC]; p++){
    acquire(&p->lock);
    if(p->pid == pid){
      p->killed = 1;
      if(p->state == SLEEPING){
        // Wake process from sleep().
        p->state = RUNNABLE;
      }
      release(&p->lock);
      return 0;
    }
    release(&p->lock);
  }
  return -1;
}

// Copy to either a user address, or kernel address,
// depending on usr_dst.
// Returns 0 on success, -1 on error.
int
either_copyout(int user_dst, uint64 dst, void *src, uint64 len)
{
  // struct proc *p = myproc();
  if(user_dst){
    // return copyout(p->pagetable, dst, src, len);
    return copyout2(dst, src, len);
  } else {
    memmove((char *)dst, src, len);
    return 0;
  }
}

// Copy from either a user address, or kernel address,
// depending on usr_src.
// Returns 0 on success, -1 on error.
int
either_copyin(void *dst, int user_src, uint64 src, uint64 len)
{
  // struct proc *p = myproc();
  if(user_src){
    // return copyin(p->pagetable, dst, src, len);
    return copyin2(dst, src, len);
  } else {
    memmove(dst, (char*)src, len);
    return 0;
  }
}

// Print a process listing to console.  For debugging.
// Runs when user types ^P on console.
// No lock to avoid wedging a stuck machine further.
void
procdump(void)
{
  static char *states[] = {
  [UNUSED]    "unused",
  [SLEEPING]  "sleep ",
