//

static inline void
plic_set_source_priority(int irq, int priority)
{
  writed(priority, PLIC_PRIORITY + irq * sizeof(uint32));
}

static inline void
plic_enable_irq_for_hart(uint64 enable_base, int irq)
{
  uint32 *enable = (uint32 *)(enable_base + (irq / 32) * sizeof(uint32));
  *enable = readd(enable) | (1U << (irq % 32));
}

void plicinit(void) {
  plic_set_source_priority(UART_IRQ, 1);
#if !defined(VISIONFIVE2)
  plic_set_source_priority(DISK_IRQ, 1);
#endif

	#ifdef DEBUG 
	printf("plicinit\n");
	#endif 
}

void
plicinithart(void)
{
  int hart = cpuid();
#ifdef VISIONFIVE2
  plic_enable_irq_for_hart(PLIC_SENABLE(hart), UART_IRQ);
  *(uint32*)PLIC_SPRIORITY(hart) = 0;
#elif defined(QEMU)
  // set uart's enable bit for this hart's S-mode. 
  *(uint32*)PLIC_SENABLE(hart)= (1 << UART_IRQ) | (1 << DISK_IRQ);
  // set this hart's S-mode priority threshold to 0.
  *(uint32*)PLIC_SPRIORITY(hart) = 0;
#else
  uint32 *hart_m_enable = (uint32*)PLIC_MENABLE(hart);
  *(hart_m_enable) = readd(hart_m_enable) | (1 << DISK_IRQ);
  uint32 *hart0_m_int_enable_hi = hart_m_enable + 1;
  *(hart0_m_int_enable_hi) = readd(hart0_m_int_enable_hi) | (1 << (UART_IRQ % 32));
#endif
  #ifdef DEBUG
  printf("plicinithart\n");
  #endif
}

// ask the PLIC what interrupt we should serve.
int
plic_claim(void)
{
  int hart = cpuid();
  int irq;
#if defined(QEMU) || defined(VISIONFIVE2)
  irq = *(uint32*)PLIC_SCLAIM(hart);
#else
  irq = *(uint32*)PLIC_MCLAIM(hart);
#endif
  return irq;
}

// tell the PLIC we've served this IRQ.
void
plic_complete(int irq)
{
  int hart = cpuid();
#if defined(QEMU) || defined(VISIONFIVE2)
  *(uint32*)PLIC_SCLAIM(hart) = irq;
#else
  *(uint32*)PLIC_MCLAIM(hart) = irq;
#endif
}

